<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('products.view');$pageTitle='Product Plans';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query('SELECT pp.*,p.name product_name FROM product_plans pp JOIN products p ON p.id=pp.product_id ORDER BY p.name,pp.price_cents')->fetchAll();?><div class="hero-actions"><h1>Product plans</h1><a class="button small" href="plan.php">New plan</a></div><div class="table-wrap"><table class="table"><thead><tr><th>Product</th><th>Plan</th><th>Hosting</th><th>Billing</th><th>Price</th><th>Activations</th><th>Updates</th><th>Support</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['product_name'])?></td><td><?=vp3_e($x['name'])?><br><small><?=vp3_e($x['plan_key'])?></small></td><td><?=vp3_e($x['hosting_type'])?></td><td><?=vp3_e($x['billing_type'].' '.$x['billing_interval'])?></td><td><?=vp3_e(vp3_money((int)$x['price_cents']))?></td><td><?=(int)$x['activation_limit']?></td><td><?=(int)$x['updates_months']?> mo</td><td><?=vp3_e($x['support_level'])?></td><td><span class="badge <?=vp3_e($x['status'])?>"><?=vp3_e($x['status'])?></span></td><td><a href="plan.php?id=<?=(int)$x['id']?>">Edit</a></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>
